function _pause() internal virtual whenNotPaused {
    _paused = true;
    emit Paused(_msgSender());
}

function disburseFee() public {
    (uint256 fee, int256 growth, uint256 abnormallyHighFeeThreshold) = _calculateFee();
    if (fee > abnormallyHighFeeThreshold) revert AbnormallyHighFee();

    _disburseFee(fee, growth, feeRecipient);
}

function _tokenExtension(uint256 tokenId) internal view override returns (address) {
    uint16 extensionIndex = uint16(_tokenData[tokenId].data);
    if (extensionIndex == 0) return address(0);
    return _indexToExtension[extensionIndex];
}

function balanceOf(address owner) public view virtual override returns (uint256) {
    require(owner != address(0), "ERC721: address zero is not a valid owner");
    return _balances[owner];
}

function ownerOf(uint256 tokenId) public view virtual override returns (address) {
    address owner = _tokenData[tokenId].owner;
    require(owner != address(0), "ERC721: invalid token ID");
    return owner;
}

function _safeTransfer(address from, address to, uint256 tokenId, bytes memory data) internal virtual {
    _transfer(from, to, tokenId);
    require(_checkOnERC721Received(from, to, tokenId, data), "ERC721: transfer to non ERC721Receiver implementer");
}

function _isApprovedOrOwner(address spender, uint256 tokenId) internal view virtual returns (bool) {
    address owner = ERC721Core.ownerOf(tokenId);
    return (spender == owner || isApprovedForAll(owner, spender) || getApproved(tokenId) == spender);
}

constructor(address implementation, bytes memory data) {
    ERC1967Utils.upgradeToAndCall(implementation, "");
    if (data.length > 0) {
        Address.functionDelegateCall(_implementation(), data);
    }
}

function _update(address from, address to, uint256 value) internal virtual override {
    if (from != address(0) && availableBalance(from) < value) revert ERC20InsufficientUnfrozenBalance(from);
    super._update(from, to, value);
}

function transferOwnership(address newOwner) public virtual override onlyOwner {
    Ownable2StepStorage storage $ = _getOwnable2StepStorage();
    $._pendingOwner = newOwner;
    emit OwnershipTransferStarted(owner(), newOwner);
}

function _beforeInitialize(address, PoolKey calldata key, uint160) internal virtual override returns (bytes4) {
    if (address(_poolKey.hooks) != address(0)) revert AlreadyInitialized();
    _poolKey = key;
    return this.beforeInitialize.selector;
}

function getVotingPowerShareOf(uint256 tokenId) public view returns (uint256) {
    uint256 totalVotingPower = _getSharedProposalStorage().governanceValues.totalVotingPower;
    return
        totalVotingPower == 0 ? 0 : (votingPowerByTokenId[tokenId] * 1e18) / totalVotingPower;
}

function _setRoleAdmin(bytes32 role, bytes32 adminRole) internal virtual {
    bytes32 previousAdminRole = _getRoleAdmin[role];
    _getRoleAdmin[role] = adminRole;
    emit RoleAdminChanged(role, previousAdminRole, adminRole);
}

function cancelListing(uint256 _listingId) external onlyExistingListing(_listingId) onlyListingCreator(_listingId) {
    _directListingsStorage().listings[_listingId].status = IDirectListings.Status.CANCELLED;
    emit CancelledListing(_msgSender(), _listingId);
}

for (uint256 i = 0; i < accountsToQuery.length; i = i.add(1)) {
  sizes[i] = bytes(accounts[accountsToQuery[i]].metadataURL).length;
  totalSize = totalSize.add(sizes[i]);
}

for (uint256 i = 0; i < bundlers.length; i++) {
    isBundlerAllowed[bundlers[i]] = allowed;
    emit BundlerAllowlistUpdated(bundlers[i], allowed);
}

if (block.chainid == _CACHED_CHAIN_ID) {
    return _CACHED_DOMAIN_SEPARATOR;
} else {
    return _buildDomainSeparator(_TYPE_HASH, _HASHED_NAME, _HASHED_VERSION);
}

for (uint256 i; i < calls.length; ++i) {
    Lookup memory lu = lookups[i];
    lu.target = target;
    lu.call = calls[i];
}

for (uint i = 0; i < authorities.length; i++) {
    if (authorities[i] == target) {
        authorities[i] = authorities[authorities.length - 1];
        authorities.length -= 1;
        break;
    }
}

vault = address(
    new MoonwellERC4626(
        ERC20(asset),
        MErc20(mToken),
        rewardRecipient,
        moontroller
    )
);

modifier initializer() {
    if (initialized) revert AlreadyInitialized();

    initialized = true;
    _;

    emit Initialized();
}

function _poke(PoolKey calldata key) internal virtual {
    poolManager.updateDynamicLPFee(key, _getFee(key));
}

constructor(address _defaultAdmin, string memory _name, string memory _symbol) ERC20Permit(_name, _symbol) {
    _setupOwner(_defaultAdmin);
}

bytes32 structHash = keccak256(
  abi.encode(EIP712_AUTHORIZE_SIGNER_TYPEHASH, account, signer, role)
);

if (_amount > 0) {
    // Transfer the LPT to the Minter
    livepeerToken().transferFrom(msg.sender, address(minter()), _amount);
}

factory = new Factory4626(
    IComptroller(addresses.getAddress("UNITROLLER")),
    addresses.getAddress("WETH")
);

constructor(uint48 _blockNumberOffset) {
    if (_blockNumberOffset < MIN_BLOCK_NUMBER_OFFSET) revert BlockNumberOffsetTooLow();
    blockNumberOffset = _blockNumberOffset;
}

require(
  _getTokenActive(tokenAddress) ||
    tokenAddress == registry.getAddressForOrDie(CELO_TOKEN_REGISTRY_ID),
  "Token needs to be active"
);

if (desiredPrice >= makerAsk.price) {
    price = desiredPrice;
} else {
    price = makerAsk.price;
}

if (token == ETH) {
    return address(this).balance;
} else {
    return ERC20(token).balanceOf(this);
}
